import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";

const DashboardCards = () => {

  const navigate = useNavigate();
  const userId = "user123";

  const [total, setTotal] = useState(0);
  const [completed, setCompleted] = useState(0);
  const [time, setTime] = useState(new Date());

  const percent =
    total === 0 ? 0 : Math.round((completed / total) * 100);

  // FETCH TODOS
  useEffect(() => {
    const fetchTodos = async () => {
      try {
        const res = await axios.get(
          `http://localhost:5001/api/todos?userId=${userId}`
        );

        const todos = res.data;

        setTotal(todos.length);

        const completedCount = todos.filter(
          (todo) => todo.completed
        ).length;

        setCompleted(completedCount);

      } catch (err) {
        console.error("DASHBOARD ERROR 👉", err);
      }
    };

    fetchTodos();
  }, []);

  // LIVE TIME
  useEffect(() => {
    const interval = setInterval(() => {
      setTime(new Date());
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  const handleAddTask = () => {
    navigate("/addTask");
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#0f172a] via-[#020617] to-[#020617] p-6">

      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        className="grid grid-cols-1 md:grid-cols-2 gap-6"
      >

        {/* 🔥 CARD 1 (TIME + INFO) */}
        <motion.div
          initial={{ y: 40, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          whileHover={{ scale: 1.03 }}
          className="relative bg-white/10 backdrop-blur-xl border border-white/20 p-6 rounded-3xl text-white shadow-2xl overflow-hidden"
        >

          <div className="absolute inset-0 bg-gradient-to-br from-indigo-500/10 to-purple-500/10 blur-2xl" />

          <div className="relative z-10 space-y-6">

            {/* Header */}
            <div>
              <h2 className="text-xl font-semibold">
                👋 Good Evening, Priyanshu
              </h2>
              <p className="text-sm opacity-70">
                Here's what's happening today
              </p>
            </div>

            {/* Time */}
            <div className="flex items-center justify-between">
              <div>
                <h1 className="text-5xl font-bold">
                  {time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </h1>
                <p className="text-sm opacity-70 mt-1">
                  {time.toDateString()}
                </p>
              </div>

              <div className="w-20 h-20 rounded-full bg-gradient-to-br from-purple-500 to-indigo-500 flex items-center justify-center">
                ⏰
              </div>
            </div>

            {/* Info Row */}
            <div className="grid grid-cols-3 gap-4 text-center text-sm">

              <div className="bg-white/5 p-3 rounded-xl">
                📅
                <p className="opacity-70">Day</p>
                <p className="font-semibold">
                  {time.toLocaleDateString('en-US', { weekday: 'long' })}
                </p>
              </div>

              <div className="bg-white/5 p-3 rounded-xl">
                🌇
                <p className="opacity-70">Focus</p>
                <p className="font-semibold">Work Time</p>
              </div>

              <div className="bg-white/5 p-3 rounded-xl">
                📍
                <p className="opacity-70">Location</p>
                <p className="font-semibold">India</p>
              </div>

            </div>

          </div>

        </motion.div>

        {/* 🔥 CARD 2 (STATS OVERVIEW) */}
        <motion.div
          initial={{ y: 40, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          whileHover={{ scale: 1.03 }}
          className="relative bg-white/10 backdrop-blur-xl border border-white/20 p-6 rounded-3xl text-white shadow-2xl overflow-hidden"
        >

          <div className="absolute inset-0 bg-gradient-to-br from-cyan-500/10 to-blue-500/10 blur-2xl" />

          <div className="relative z-10 space-y-6">

            <h2 className="text-lg font-semibold">📊 Today's Overview</h2>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 gap-4">

              <div className="bg-white/5 p-4 rounded-xl text-center">
                📋
                <p className="text-2xl font-bold">{total}</p>
                <p className="text-xs opacity-70">Total Tasks</p>
              </div>

              <div className="bg-white/5 p-4 rounded-xl text-center">
                ✅
                <p className="text-2xl font-bold text-green-400">{completed}</p>
                <p className="text-xs opacity-70">Completed</p>
              </div>

              <div className="bg-white/5 p-4 rounded-xl text-center">
                ⏳
                <p className="text-2xl font-bold text-yellow-300">{total - completed}</p>
                <p className="text-xs opacity-70">Remaining</p>
              </div>

              <div className="bg-white/5 p-4 rounded-xl text-center">
                📈
                <p className="text-2xl font-bold text-blue-400">{percent}%</p>
                <p className="text-xs opacity-70">Progress</p>
              </div>

            </div>

            {/* Progress Bar */}
            <div>
              <div className="w-full h-2 bg-white/20 rounded-full overflow-hidden">
                <motion.div
                  initial={{ width: 0 }}
                  animate={{ width: `${percent}%` }}
                  transition={{ duration: 1 }}
                  className="h-full bg-gradient-to-r from-purple-500 to-indigo-500"
                />
              </div>
            </div>

            {/* Motivation */}
            <div className="bg-gradient-to-r from-purple-500/20 to-pink-500/20 p-4 rounded-xl text-center text-sm">
              {percent === 100
                ? "🔥 All tasks completed!"
                : "🚀 Small progress is still progress"}
            </div>

            <button
              onClick={handleAddTask}
              className="w-full py-2 bg-white text-black rounded-xl font-semibold hover:scale-105 transition"
            >
              + Add Task
            </button>

          </div>

        </motion.div>

      </motion.div>

    </div>
  );
};

export default DashboardCards;
